const amqplib = require('amqplib');

// RabbitMQ connection settings
const rabbitUrl = 'amqp://localhost';
const exchangeName = 'payment_exchange';
const queueName = 'payment_queue';

async function connectToRabbitMq() {
  try {
    const conn = await amqplib.connect(rabbitUrl);
    const channel = await conn.createChannel();
    return { conn, channel };
  } catch (err) {
    console.error('Error connecting to RabbitMQ:', err);
    process.exit(1);
  }
}

async function consumeMessages({ channel }) {
  try {
    // Declare the exchange and queue
    await channel.assertExchange(exchangeName, 'direct', { durable: true });
    await channel.assertQueue(queueName, { durable: true });

    // Bind the queue to the exchange
    await channel.bindQueue(queueName, exchangeName, '', '', false);

    // Consume messages from the queue
    const msg = await channel.get(queueName);
    if (msg !== null) {
      console.log('Received message:', msg.content.toString());
      processPaymentMessage(msg.content.toString());
      await channel.ack(msg);
    }
  } catch (err) {
    console.error('Error consuming messages:', err);
  }
}

async function processPaymentMessage(message) {
  try {
    // Parse the payment event from the message content
    const paymentEvent = JSON.parse(message);

    // Validate the payment event data
    if (!paymentEvent.amount || !paymentEvent.currency) {
      console.error('Invalid payment event:', paymentEvent);
      return;
    }

    // Execute payment logic based on the message content
    const paymentResult = await executePayment(paymentEvent);
    console.log('Payment result:', paymentResult);

    // Log sensitive data securely (e.g., using a logging library with encryption)
    console.log(`Payment ${paymentEvent.id} processed successfully.`);
  } catch (err) {
    console.error('Error processing payment message:', err);
  }
}

async function executePayment(paymentEvent) {
  try {
    // Simulate payment processing logic
    return { status: 'success', id: paymentEvent.id };
  } catch (err) {
    console.error('Error executing payment:', err);
    throw err;
  }
}

